def show_receipt(items):
    total = 0
    print('=== RECEIPT ===')
    for item in items:
        print(item['name'] + ': $' + str(item['price']))
        total = total + item['price']
    print('Total: $' + str(total))

# With input() you'd write: new_name = input('Add an item: ')
# But this example uses a preset value so it runs without waiting:
cart = [
    {'name': 'Apple', 'price': 1},
    {'name': 'Banana', 'price': 2},
    {'name': 'Orange', 'price': 1}
]

if len(cart) > 5:
    print('Your cart is full!')
else:
    show_receipt(cart)
